package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareHandlerActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_handler)

        handleIncomingShare(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleIncomingShare(intent)
    }

    private fun handleIncomingShare(intent: Intent) {
        when (intent.action) {
            Intent.ACTION_SEND -> {
                intent.type?.let { type ->
                    when {
                        type.startsWith("text/") -> handleSendText(intent)
                        type.startsWith("image/") -> handleSendImage(intent)
                    }
                }
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                intent.type?.let { type ->
                    if (type.startsWith("image/")) {
                        handleSendMultipleImages(intent)
                    }
                }
            }
        }
    }

    private fun handleSendText(intent: Intent) {
        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { sharedText ->
            // Process the shared text (URL)
            Toast.makeText(this, "Received URL: $sharedText", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSendImage(intent: Intent) {
        (intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))?.let { imageUri ->
            // Process the shared image
            Toast.makeText(this, "Received Image: $imageUri", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleSendMultipleImages(intent: Intent) {
        intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)?.let { imageUris ->
            // Process the shared images
            Toast.makeText(this, "Received Multiple Images: $imageUris", Toast.LENGTH_SHORT).show()
        }
    }
}